public static void main(Args args)
{
    System.IO.MemoryStream memoryStream = new System.IO.MemoryStream();

    using (var package = new OfficeOpenXml.ExcelPackage(memoryStream))
    {

        var currentRow = 1;
        var worksheets                  = package.get_Workbook().get_Worksheets();
        var paymentUploader             = worksheets.Add("ExcelSheet");
        var cells                       = paymentUploader.get_Cells();

        OfficeOpenXml.ExcelRange cell = cells.get_Item(currentRow, 1);
        System.String value = "Settlement Number";
        cell.set_Value(value);
        var column = cell.get_Worksheet().Column(cell.get_Start().get_Column());
        var columnStyle = column.get_Style();
        var columnNumberFormat =  columnStyle.get_Numberformat();
        columnNumberFormat.set_Format("@");

        cell = null;
        value = "Voucher";
        cell = cells.get_Item(currentRow, 2);
        cell.set_Value(value);
        column = cell.get_Worksheet().Column(cell.get_Start().get_Column());
        columnStyle = column.get_Style();
        columnNumberFormat =  columnStyle.get_Numberformat();
        columnNumberFormat.set_Format("@");

        cell = null;
        value = "Settlement Amount";
        cell = cells.get_Item(currentRow, 3);
        cell.set_Value(value);
        column = cell.get_Worksheet().Column(cell.get_Start().get_Column());
        columnStyle = column.get_Style();
        columnNumberFormat =  columnStyle.get_Numberformat();
        columnNumberFormat.set_Format("@");

        cell = null;
        value = "Settlement Date";
        cell = cells.get_Item(currentRow, 4);
        cell.set_Value(value);
        column = cell.get_Worksheet().Column(cell.get_Start().get_Column());
        columnStyle = column.get_Style();
        columnNumberFormat =  columnStyle.get_Numberformat();
        columnNumberFormat.set_Format("@");

        cell = null;
        value = "Module Type";
        cell = cells.get_Item(currentRow, 5);
        cell.set_Value(value);
        column = cell.get_Worksheet().Column(cell.get_Start().get_Column());
        columnStyle = column.get_Style();
        columnNumberFormat =  columnStyle.get_Numberformat();
        columnNumberFormat.set_Format("@");

        package.Save();
        file::SendFileToUser(memoryStream, "Payment uploader template.xlsx");
    }
}
